import React from 'react';

import './parser.css';

import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faFile, faUpload } from '@fortawesome/free-solid-svg-icons';

const Parser = () => {
	return (
		<div className='parser'>
			<div className="options">
				<button className='icon'><FontAwesomeIcon icon={faFile} /></button>
				<button className='icon'><FontAwesomeIcon icon={faUpload} /></button>
				<button className='icon'>About</button>
			</div>
		</div>
	)
}

export default Parser;
